def _detect_default_gpu_arch():
    amdgpu_arch = _find_rocm_bin("amdgpu-arch")
    if amdgpu_arch:
        out = subprocess.run(
            [amdgpu_arch], capture_output=True, text=True, check=False
        ).stdout.strip()
        archs = [a for a in out.split("\n") if a]
        if archs:
            return archs[0]
    return "gfx950"


DEFAULT_GPU_ARCH = _detect_default_gpu_arch()
GPU_ARCH = os.environ.get("GPU_ARCHS", DEFAULT_GPU_ARCH) or DEFAULT_GPU_ARCH

def get_hip_version():
    hipconfig = _find_rocm_bin("hipconfig")
    if hipconfig is None:
        raise RuntimeError(
            "hipconfig not found; set ROCM_PATH/ROCM_HOME or add hipconfig to PATH"
        )
    version = subprocess.run(
        [hipconfig, "--version"], capture_output=True, text=True, check=False
    )
    parts = version.stdout.split()
    if not parts:
        raise RuntimeError(
            f"`{hipconfig} --version` returned no output "
            f"(rc={version.returncode}, stderr={version.stderr!r})"
        )
    return parse(parts[-1].rstrip("-").replace("-", "+"))

